local StructServer = LxClass("StructServer", nil)

function StructServer:StructServer()
    self.serverId = 0                    --服务器Id
    self.serverName = ""                 --服务器名称
    self.worldLevel = 0                  --世界等级
    self.reportUrl = ""                  --子服战报地址

end

function StructServer:CreateByPb(pb, isReplace)
    self.serverId = pb.serverId

    self.worldLevel = pb.worldLevel
